    // Calculate (n+m)/2 factorial
    factorial = 1;
    for (i = 2; i <= (n + m) / 2; ++i) {
        factorial *= i;
    }

    let denominator1 = factorial; // ((n+m)/2)!

    // Calculate (n-m)/2 factorial
